125→    @SuppressLint("ClickableViewAccessibility")
126→    private fun StatsFragmentBinding.initializeViewModels(
127→        activity: FragmentActivity,
128→        isFirstStart: Boolean,
129→        savedInstanceState: Bundle?
130→    ) {
131→        viewModel.onRestoreInstanceState(savedInstanceState)
132→
133→        setupObservers(activity)
134→
135→        viewModel.start(activity.intent)
136→
137→        if (!isFirstStart) {
138→            restorePreviousSearch = true
139→        }
140→
141→        statsPager.setOnTouchListener { _, event ->
142→            swipeToRefreshHelper.setEnabled(false)
143→            if (event.action == MotionEvent.ACTION_UP) {
144→                swipeToRefreshHelper.setEnabled(true)
145→            }
146→            return@setOnTouchListener false
147→        }
148→
149→        viewModel.showJetpackPoweredBottomSheet.observeEvent(viewLifecycleOwner) {
150→            if (isFirstStart) {
151→                JetpackPoweredBottomSheetFragment
152→                    .newInstance(it, MY_SITE)
153→                    .show(childFragmentManager, JetpackPoweredBottomSheetFragment.TAG)
154→            }
155→        }
156→
157→        viewModel.showJetpackOverlay.observeEvent(viewLifecycleOwner) {
158→            if (isFirstStart) {
159→                JetpackFeatureFullScreenOverlayFragment
160→                    .newInstance(JetpackFeatureOverlayScreenType.STATS)
161→                    .show(childFragmentManager, JetpackFeatureFullScreenOverlayFragment.TAG)
