253→    private fun StatsFragmentBinding.handleSelectedSection(
254→        selectedSection: StatsSection
255→    ) {
256→        val position = when (selectedSection) {
257→            INSIGHTS -> 0
258→            DAYS -> 1
259→            WEEKS -> 2
260→            MONTHS -> 3
261→            YEARS -> 4
262→            DETAIL,
263→            INSIGHT_DETAIL,
264→            TOTAL_LIKES_DETAIL,
265→            TOTAL_COMMENTS_DETAIL,
266→            TOTAL_FOLLOWERS_DETAIL,
267→            ANNUAL_STATS -> null
268→            else -> null
269→        }
270→        position?.let {
271→            if (statsPager.currentItem != position) {
272→                tabLayout.removeOnTabSelectedListener(selectedTabListener)
273→                statsPager.setCurrentItem(position, false)
274→                tabLayout.addOnTabSelectedListener(selectedTabListener)
275→            }
276→        }
277→    }
